INSERT INTO career_trees (person_name, person_name_en, person_title, stages_json, display_priority) VALUES ('아이유', 'IU', '싱어송라이터', '[{"order":0,"title":"로엔엔터테인먼트 연습생 입소","organization":"로엔엔터테인먼트","years":"2007","description":"중학교 재학 중 프로듀서 최갑원의 눈에 띄어 오디션에 합격, 로엔엔터테인먼트 소속 연습생으로 입소하여 약 10개월간 보컬 트레이닝을 받았다.","job_slug":null},{"order":1,"title":"만 15세에 정식 데뷔","organization":"로엔엔터테인먼트","years":"2008","description":"2008년 9월 Mnet M! Countdown에서 데뷔 싱글 미아를 발표하고, 첫 번째 미니앨범 Lost and Found를 발매하며 가요계에 입문했다.","job_slug":"가수"},{"order":2,"title":"좋은 날 히트로 대중적 인지도 확보","organization":"","years":"2010-2011","description":"2010년 좋은 날이 음원 차트 정상을 석권하며 대중적 인지도를 확보했다. 빌보드가 선정한 2010년대 K-pop 명곡 1위.","job_slug":null},{"order":3,"title":"싱어송라이터로 독자적 음악 색채 정립","organization":"","years":"2013-2017","description":"꽃갈피(2014), Chat-shire(2015), Palette(2017)를 연달아 발표하며 싱어송라이터로서의 정체성을 구축했다.","job_slug":null},{"order":4,"title":"정규 5집 LILAC 월드투어로 정상 유지","organization":"","years":"2021-현재","description":"2021년 정규 5집 LILAC 발표. 2024년 12개국 18개 도시 31회 공연으로 50만 명 이상의 관객을 동원하며 국내 최정상 솔로 아티스트 지위를 유지.","job_slug":null}]', 100);
INSERT INTO career_trees (person_name, person_name_en, person_title, stages_json, display_priority) VALUES ('조용필', 'Cho Yong-pil', '가왕 싱어송라이터', '[{"order":0,"title":"밴드 활동 및 미8군 무대 데뷔","organization":"화이브 핑거스","years":"1968-1969","description":"경동고등학교 졸업 후 애트킨즈에서 기타리스트로 활동하다가 1969년 화이브 핑거스를 결성해 미 8군 무대에서 음악 경력을 시작했다.","job_slug":null},{"order":1,"title":"돌아와요 부산항에 발표 및 가수 공식 데뷔","organization":"지구레코드","years":"1975-1979","description":"1975년 돌아와요 부산항에를 발표해 주목받았다. 1979년 해금 후 그룹 위대한 탄생을 결성하고 지구레코드와 전속 계약을 맺으며 공식 데뷔했다.","job_slug":"가수"},{"order":2,"title":"정규 1집 창밖의 여자 한국 최초 밀리언셀러","organization":"","years":"1980","description":"1980년 정규 1집을 발매하고 창밖의 여자가 대히트. 한국 대중음악 사상 최초의 단일 음반 밀리언셀러.","job_slug":null},{"order":3,"title":"연속 밀리언셀러로 가왕 등극","organization":"","years":"1980년대","description":"1980년대에 걸쳐 정규앨범을 연달아 발표하며 1994년 국내 최초로 누적 음반 판매량 1000만 장을 돌파. 가왕 칭호를 얻었다.","job_slug":null},{"order":4,"title":"19집 Hello 20집으로 세대 초월 입증","organization":"","years":"2013-현재","description":"2013년 정규 19집 Hello로 23년 만에 지상파 음악 프로그램 1위. 2024년 11년 만의 정규 20집을 발표하며 현역 최정상 가수로서의 위상을 재확인했다.","job_slug":null}]', 90);